import React, { useState, useEffect } from 'react';
import { useLocation } from 'react-router-dom';
import { Card, CardContent, CardHeader, CardTitle } from '../components/ui/Card';
import { Input } from '../components/ui/Input';
import { Button } from '../components/ui/Button';
import { Badge } from '../components/ui/Badge';
import { Search, Globe, Target, TrendingUp, Sparkles, MoveRight, Loader2, ArrowUpRight } from 'lucide-react';

export const Insights = () => {
  const location = useLocation();
  const [industry, setIndustry] = useState('');
  const [isFetchingSignals, setIsFetchingSignals] = useState(false);
  const [signals, setSignals] = useState([]);

  // Simulation of the AI Insights API Response
  const [aiInsights, setAiInsights] = useState(null);

  useEffect(() => {
    // If we routed here from 'Analyze Data' in Upload page
    if (location.state?.analyzed) {
      loadInsightsMock();
    }
  }, [location.state]);

  const loadInsightsMock = () => {
    setAiInsights({
      internal_analysis: "Revenue has grown 20% MoM, but customer acquisition cost (CAC) for SMBs has increased by 15%. Churn remains stable at 2.1%.",
      market_connection: "High correlation between the recent drop in overall SaaS spending globally and your extended sales cycles for enterprise clients. However, localized SMB tech adoption is surging.",
      forecast: "Expect a 12% revenue growth next quarter, driven mostly by existing customer expansions rather than net-new enterprise logos. Risk of churn in the retail sector if consumer spending dips further."
    });
  };

  const handleFetchSignals = (e) => {
    e.preventDefault();
    if (!industry) return;

    setIsFetchingSignals(true);
    // Simulate fetching
    setTimeout(() => {
      setSignals([
        { title: "SaaS Spending Consolidation", summary: "Companies are reducing overlapping toolsets by 22% on average.", source: "Gartner", trend: "down" },
        { title: "AI Integration Boom", summary: "78% of enterprises plan to increase budgets for AI-embedded reporting tools.", source: "Forrester", trend: "up" },
        { title: "Remote Work Normalization", summary: "Office space demand has stabilized, maintaining distributed team models.", source: "WSJ", trend: "neutral" }
      ]);

      // If no AI insights are loaded yet, we can load a mock based on the signal
      if (!aiInsights) {
        loadInsightsMock();
      }
      setIsFetchingSignals(false);
    }, 2000);
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700 ease-out max-w-6xl mx-auto w-full">
      <div>
        <h1 className="text-3xl font-bold text-white tracking-tight flex items-center">
          <Sparkles className="w-8 h-8 mr-3 text-accent" />
          AI Insights & Market Intelligence
        </h1>
        <p className="text-slate-400 mt-2 text-lg">Combine your internal metrics with external signals for predictive forecasting.</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Left Column: Signals & Input */}
        <div className="lg:col-span-1 space-y-6">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center text-lg">
                <Globe className="w-5 h-5 mr-2 text-accent" />
                External Market Signals
              </CardTitle>
              <p className="text-sm text-slate-400">Fetch real-time macro trends affecting your sector.</p>
            </CardHeader>
            <CardContent>
              <form onSubmit={handleFetchSignals} className="space-y-4">
                <div className="space-y-2">
                  <label className="text-sm font-medium text-slate-300">Industry Sector</label>
                  <div className="relative">
                    <Search className="w-4 h-4 absolute left-3 top-3 text-slate-500" />
                    <Input 
                      placeholder="e.g. SaaS, Real Estate..." 
                      className="pl-9"
                      value={industry}
                      onChange={(e) => setIndustry(e.target.value)}
                    />
                  </div>
                </div>
                <Button type="submit" className="w-full" disabled={!industry || isFetchingSignals}>
                  {isFetchingSignals ? (
                    <><Loader2 className="w-4 h-4 mr-2 animate-spin" /> Fetching...</>
                  ) : (
                    "Fetch Market Trends"
                  )}
                </Button>
              </form>
            </CardContent>
          </Card>

          {signals.length > 0 && (
            <div className="space-y-4 animate-in fade-in slide-in-from-left-4 duration-500">
              <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-widest px-1">Latest Signals</h3>
              {signals.map((signal, i) => (
                <Card key={i} className="bg-slate-800/20 border-slate-700/40 hover:bg-slate-800/40 transition-colors">
                  <CardContent className="p-4 space-y-2">
                    <div className="flex justify-between items-start">
                      <h4 className="font-semibold text-white text-sm pr-2 leading-tight">{signal.title}</h4>
                      <Badge variant={signal.trend === 'up' ? 'success' : signal.trend === 'down' ? 'warning' : 'default'} className="shrink-0 text-[10px] py-0">
                        {signal.source}
                      </Badge>
                    </div>
                    <p className="text-xs text-slate-400 leading-relaxed">{signal.summary}</p>
                  </CardContent>
                </Card>
              ))}
            </div>
          )}
        </div>

        {/* Right Column: AI Analysis */}
        <div className="lg:col-span-2 space-y-6">
          {!aiInsights ? (
            <Card className="h-full flex flex-col items-center justify-center min-h-[400px] border-dashed bg-transparent border-slate-700">
              <div className="w-16 h-16 rounded-full bg-slate-800 flex items-center justify-center mb-4">
                <Target className="w-8 h-8 text-slate-500" />
              </div>
              <h3 className="text-xl font-semibold text-white">No active analysis</h3>
              <p className="text-slate-400 text-center max-w-sm mt-2">Upload your data or fetch market signals to generate a comprehensive AI business report.</p>
            </Card>
          ) : (
            <div className="space-y-6 animate-in fade-in zoom-in-95 duration-500">
              <Card className="border-accent/30 bg-gradient-to-br from-slate-900 via-[#1E293B] to-slate-900 relative overflow-hidden">
                <div className="absolute top-0 right-0 p-32 bg-accent/5 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>
                <CardHeader>
                  <CardTitle className="flex items-center text-xl">
                    <Target className="w-6 h-6 mr-3 text-accent" />
                    Internal Analysis
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="text-slate-300 leading-relaxed text-lg">
                    {aiInsights.internal_analysis}
                  </p>
                </CardContent>
              </Card>

              <div className="flex justify-center -my-3 relative z-10">
                <div className="bg-slate-800 p-2 rounded-full border border-slate-700">
                  <MoveRight className="w-5 h-5 text-slate-400 transform rotate-90" />
                </div>
              </div>

              <Card>
                <CardHeader>
                  <CardTitle className="flex items-center text-xl">
                    <Globe className="w-6 h-6 mr-3 text-emerald-500" />
                    Market Connection
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="text-slate-300 leading-relaxed text-lg">
                    {aiInsights.market_connection}
                  </p>
                </CardContent>
              </Card>

              <div className="flex justify-center -my-3 relative z-10">
                <div className="bg-slate-800 p-2 rounded-full border border-slate-700">
                  <MoveRight className="w-5 h-5 text-slate-400 transform rotate-90" />
                </div>
              </div>

              <Card className="border-emerald-500/30 shadow-[0_0_30px_-15px_rgba(16,185,129,0.3)] bg-gradient-to-b from-slate-900 to-[#0f1f1a]">
                <CardHeader>
                  <CardTitle className="flex items-center text-2xl text-white">
                    <TrendingUp className="w-7 h-7 mr-3 text-emerald-500" />
                    Future Forecast
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="text-emerald-100 leading-relaxed text-lg font-medium">
                    {aiInsights.forecast}
                  </p>

                  <div className="mt-8 pt-6 border-t border-emerald-500/20 flex flex-wrap gap-3">
                    <Badge variant="success" className="px-3 py-1 flex items-center text-sm">
                      <ArrowUpRight className="w-4 h-4 mr-1" /> +12% Growth Projected
                    </Badge>
                    <Badge variant="warning" className="px-3 py-1 text-sm bg-slate-800 text-slate-300 border-slate-600">High Confidence</Badge>
                  </div>
                </CardContent>
              </Card>
            </div>
          )}
        </div>

      </div>
    </div>
  );
};
